// Strange Attractors - Mathematical Light Trails

let trails = [];
let prevType = '';
let angleX = 0;
let angleY = 0;
let firstFrame = true;

const PALETTES = {
  electric: [[0,150,255],[0,255,200],[100,0,255],[255,255,255],[0,220,255]],
  fire: [[255,60,0],[255,160,0],[255,220,50],[255,100,50],[200,0,0]],
  ice: [[100,180,255],[200,230,255],[150,200,240],[220,240,255],[80,140,220]],
  aurora: [[0,255,120],[0,200,255],[120,0,255],[255,0,180],[0,255,200]],
  sunset: [[255,80,50],[255,150,50],[255,200,100],[200,50,80],[255,120,80]],
  vapor: [[255,100,200],[100,200,255],[200,150,255],[150,255,200],[255,180,220]],
  acid: [[0,255,0],[180,255,0],[0,255,120],[200,255,50],[100,255,0]],
  phantom: [[150,150,180],[100,100,140],[200,200,220],[80,80,120],[180,170,200]]
};

function getTrailCount(v) {
  const m = {single:1, few:3, several:6, many:12, swarm:24, cloud:48};
  return m[v] || 3;
}

function getTrailLen(v) {
  const m = {short:80, medium:200, long:500, flowing:1000, infinite:5000, flash:20};
  return m[v] || 200;
}

function getLineW(v) {
  const m = {hairline:1, fine:1.5, medium:2, bold:3, heavy:5, variable:-1};
  return m[v] || 1;
}

function getFadeAlpha(v) {
  const m = {none:0, slow:3, medium:8, fast:25, instant:200, strobe:-1};
  return m[v] || 15;
}

function getRotSpeed(v) {
  const m = {none:0, slow:0.003, medium:0.008, fast:0.02, oscillating:-1, chaotic:-2};
  return m[v] || 0;
}

function getPerturbAmt(v) {
  const m = {none:0, subtle:0.01, moderate:0.05, wild:0.15, explosive:0.4, breathing:-1};
  return m[v] || 0;
}

function stepAttractor(type, x, y, z, dt, perturb) {
  let dx, dy, dz;
  let pp = perturb;
  if (type === 'lorenz') {
    let sigma = 10 + pp * 5, rho = 28 + pp * 10, beta = 8/3 + pp;
    dx = sigma * (y - x);
    dy = x * (rho - z) - y;
    dz = x * y - beta * z;
    return [x + dx*dt, y + dy*dt, z + dz*dt];
  } else if (type === 'clifford') {
    let a = -1.4 + pp, b = 1.6 + pp*0.5, c = 1.0 - pp*0.3, d = 0.7 + pp*0.2;
    dx = Math.sin(a * y) + c * Math.cos(a * x);
    dy = Math.sin(b * x) + d * Math.cos(b * y);
    return [dx, dy, z * 0.99];
  } else if (type === 'dejong') {
    let a = -2.0 + pp, b = -2.0 - pp*0.3, c = -1.2 + pp*0.5, d = 2.0 - pp*0.2;
    dx = Math.sin(a * y) - Math.cos(b * x);
    dy = Math.sin(c * x) - Math.cos(d * y);
    return [dx, dy, z * 0.99];
  } else if (type === 'rossler') {
    let a = 0.2 + pp*0.1, b = 0.2 + pp*0.05, c = 5.7 + pp*2;
    dx = -(y + z);
    dy = x + a * y;
    dz = b + z * (x - c);
    return [x + dx*dt, y + dy*dt, z + dz*dt];
  } else if (type === 'aizawa') {
    let a = 0.95, b = 0.7 + pp*0.1, c = 0.6, d = 3.5, e = 0.25, f = 0.1;
    dx = (z - b) * x - d * y;
    dy = d * x + (z - b) * y;
    dz = c + a * z - z*z*z/3 - (x*x + y*y) * (1 + e*z) + f * z * x*x*x;
    return [x + dx*dt, y + dy*dt, z + dz*dt];
  } else if (type === 'thomas') {
    let b = 0.208186 + pp*0.05;
    dx = Math.sin(y) - b * x;
    dy = Math.sin(z) - b * y;
    dz = Math.sin(x) - b * z;
    return [x + dx*dt*5, y + dy*dt*5, z + dz*dt*5];
  } else if (type === 'halvorsen') {
    let a = 1.89 + pp*0.3;
    dx = -a*x - 4*y - 4*z - y*y;
    dy = -a*y - 4*z - 4*x - z*z;
    dz = -a*z - 4*x - 4*y - x*x;
    return [x + dx*dt, y + dy*dt, z + dz*dt];
  } else { // dadras
    let a=3,b=2.7+pp*0.5,c=1.7,d=2,e=9;
    dx = y - a*x + b*y*z;
    dy = c*y - x*z + z;
    dz = d*x*y - e*z;
    return [x + dx*dt*0.5, y + dy*dt*0.5, z + dz*dt*0.5];
  }
}

function getStartPos(type) {
  if (type === 'clifford' || type === 'dejong') return [0.1, 0.1, 0];
  if (type === 'lorenz') return [1, 1, 1];
  if (type === 'rossler') return [1, 1, 0];
  if (type === 'aizawa') return [0.1, 0, 0];
  if (type === 'thomas') return [1, 0, 0];
  if (type === 'halvorsen') return [-1.5, 0, 0];
  return [1, 0.5, 0.5];
}

function getScale(type) {
  if (type === 'clifford' || type === 'dejong') return 100;
  if (type === 'lorenz') return 7;
  if (type === 'rossler') return 12;
  if (type === 'aizawa') return 120;
  if (type === 'thomas') return 80;
  if (type === 'halvorsen') return 12;
  return 20;
}

function getDt(type) {
  if (type === 'clifford' || type === 'dejong') return 1;
  if (type === 'lorenz') return 0.005;
  if (type === 'rossler') return 0.01;
  if (type === 'aizawa') return 0.005;
  if (type === 'thomas') return 0.03;
  if (type === 'halvorsen') return 0.003;
  return 0.005;
}

function project(x, y, z, scale, aX, aY) {
  let cosX = Math.cos(aX), sinX = Math.sin(aX);
  let cosY = Math.cos(aY), sinY = Math.sin(aY);
  let y1 = y * cosX - z * sinX;
  let z1 = y * sinX + z * cosX;
  let x1 = x * cosY - z1 * sinY;
  return [300 + x1 * scale, 300 + y1 * scale, z1];
}

function samplePalette(palette, t) {
  t = ((t % 1) + 1) % 1;
  let idx = t * (palette.length - 1);
  let i = Math.floor(idx);
  let f = idx - i;
  let c1 = palette[Math.min(i, palette.length - 1)];
  let c2 = palette[Math.min(i + 1, palette.length - 1)];
  return [c1[0]+(c2[0]-c1[0])*f, c1[1]+(c2[1]-c1[1])*f, c1[2]+(c2[2]-c1[2])*f];
}

p.setup = function() {
  p.createCanvas(600, 600);
  p.background(0);
};

p.draw = function() {
  let typeV = p.getSynthVar('attractor_type') || 'lorenz';
  let countV = p.getSynthVar('trail_count') || 'few';
  let lenV = p.getSynthVar('trail_length') || 'medium';
  let cmodeV = p.getSynthVar('color_mode') || 'velocity';
  let palV = p.getSynthVar('color_palette') || 'electric';
  let lwV = p.getSynthVar('line_weight') || 'fine';
  let fadeV = p.getSynthVar('background_fade') || 'medium';
  let rotV = p.getSynthVar('rotation') || 'slow';
  let pertV = p.getSynthVar('perturbation') || 'none';
  let rsV = p.getSynthVar('render_style') || 'lines';

  let nTrails = getTrailCount(countV);
  let maxLen = getTrailLen(lenV);
  let palette = PALETTES[palV] || PALETTES.electric;
  let lw = getLineW(lwV);
  let fadeAlpha = getFadeAlpha(fadeV);
  let rotSpeed = getRotSpeed(rotV);
  let pertAmt = getPerturbAmt(pertV);
  let scale = getScale(typeV);
  let dt = getDt(typeV);

  // Reset trails if attractor type or count changed
  if (typeV !== prevType || trails.length !== nTrails || firstFrame) {
    prevType = typeV;
    firstFrame = false;
    trails = [];
    let start = getStartPos(typeV);
    for (let i = 0; i < nTrails; i++) {
      trails.push({
        x: start[0] + (Math.random() - 0.5) * 0.5,
        y: start[1] + (Math.random() - 0.5) * 0.5,
        z: start[2] + (Math.random() - 0.5) * 0.5,
        history: [],
        hue: i / nTrails
      });
    }
    p.background(0);
    angleX = 0;
    angleY = 0;
  }

  // Background fade
  if (fadeAlpha > 0 && fadeAlpha < 200) {
    p.fill(0, 0, 0, fadeAlpha);
    p.noStroke();
    p.rect(0, 0, 600, 600);
  } else if (fadeAlpha >= 200) {
    p.background(0);
  } else if (fadeAlpha === -1) { // strobe
    if (p.frameCount % 10 < 2) p.background(0);
  }

  // Rotation
  if (rotSpeed === -1) { // oscillating
    angleY = Math.sin(p.frameCount * 0.01) * 0.8;
    angleX = Math.cos(p.frameCount * 0.007) * 0.4;
  } else if (rotSpeed === -2) { // chaotic
    angleY += Math.sin(p.frameCount * 0.03) * 0.01;
    angleX += Math.cos(p.frameCount * 0.02) * 0.008;
  } else {
    angleY += rotSpeed;
    angleX += rotSpeed * 0.3;
  }

  // Perturbation
  let currentPerturb = 0;
  if (pertAmt === -1) { // breathing
    currentPerturb = Math.sin(p.frameCount * 0.02) * 0.1;
  } else {
    currentPerturb = pertAmt * (Math.sin(p.frameCount * 0.05) * 0.5 + 0.5);
  }

  // Step and draw trails
  let stepsPerFrame = (typeV === 'clifford' || typeV === 'dejong') ? 30 : 15;

  for (let t = 0; t < trails.length; t++) {
    let trail = trails[t];

    for (let s = 0; s < stepsPerFrame; s++) {
      let next = stepAttractor(typeV, trail.x, trail.y, trail.z, dt, currentPerturb);
      // Clamp to prevent explosion
      if (Math.abs(next[0]) > 1000 || Math.abs(next[1]) > 1000 || Math.abs(next[2]) > 1000) {
        let start = getStartPos(typeV);
        next = [start[0] + (Math.random()-0.5)*0.5, start[1] + (Math.random()-0.5)*0.5, start[2] + (Math.random()-0.5)*0.5];
      }

      let prev2d = project(trail.x, trail.y, trail.z, scale, angleX, angleY);
      trail.x = next[0]; trail.y = next[1]; trail.z = next[2];
      let cur2d = project(trail.x, trail.y, trail.z, scale, angleX, angleY);

      trail.history.push([cur2d[0], cur2d[1], cur2d[2],
        Math.sqrt((next[0]-trail.x)**2 + (next[1]-trail.y)**2 + (next[2]-trail.z)**2)]);
      if (trail.history.length > maxLen) trail.history.shift();

      // Color
      let colorT = 0;
      if (cmodeV === 'velocity') {
        let vel = Math.sqrt((next[0]-trail.x)**2+(next[1]-trail.y)**2+(next[2]-trail.z)**2);
        colorT = (vel * 100) % 1;
      } else if (cmodeV === 'position') {
        colorT = ((trail.x + trail.y) * 0.05 + 0.5) % 1;
      } else if (cmodeV === 'age') {
        colorT = trail.history.length / maxLen;
      } else if (cmodeV === 'angle') {
        colorT = (Math.atan2(cur2d[1] - 300, cur2d[0] - 300) / (Math.PI * 2) + 1) % 1;
      } else if (cmodeV === 'rainbow_cycle') {
        colorT = (p.frameCount * 0.005 + trail.hue) % 1;
      } else { // depth
        colorT = (cur2d[2] * 0.02 + 0.5) % 1;
      }
      colorT = ((colorT % 1) + 1) % 1;
      let col = samplePalette(palette, colorT);

      let lineW = lw === -1 ? (0.5 + Math.abs(Math.sin(s * 0.3)) * 3) : lw;
      let alpha = fadeAlpha === 0 ? 80 : Math.min(255, 160 + 60 * (1 - trail.history.length / maxLen));

      if (rsV === 'points') {
        p.noStroke();
        p.fill(col[0], col[1], col[2], alpha);
        p.circle(cur2d[0], cur2d[1], lineW * 2);
      } else if (rsV === 'glow') {
        p.stroke(col[0], col[1], col[2], alpha * 0.2);
        p.strokeWeight(lineW * 4);
        p.line(prev2d[0], prev2d[1], cur2d[0], cur2d[1]);
        p.stroke(col[0], col[1], col[2], alpha);
        p.strokeWeight(lineW);
        p.line(prev2d[0], prev2d[1], cur2d[0], cur2d[1]);
      } else if (rsV === 'ribbon') {
        let nx = -(cur2d[1] - prev2d[1]);
        let ny = cur2d[0] - prev2d[0];
        let len = Math.sqrt(nx*nx+ny*ny) || 1;
        nx /= len; ny /= len;
        let w = lineW * 2;
        p.fill(col[0], col[1], col[2], alpha * 0.6);
        p.noStroke();
        p.quad(prev2d[0]+nx*w, prev2d[1]+ny*w, prev2d[0]-nx*w, prev2d[1]-ny*w,
               cur2d[0]-nx*w, cur2d[1]-ny*w, cur2d[0]+nx*w, cur2d[1]+ny*w);
      } else if (rsV === 'dotted') {
        if (s % 3 === 0) {
          p.noStroke();
          p.fill(col[0], col[1], col[2], alpha);
          p.circle(cur2d[0], cur2d[1], lineW * 2.5);
        }
      } else if (rsV === 'pixelated') {
        p.noStroke();
        p.fill(col[0], col[1], col[2], alpha);
        let px = Math.floor(cur2d[0] / 4) * 4;
        let py = Math.floor(cur2d[1] / 4) * 4;
        p.rect(px, py, 4, 4);
      } else { // lines
        p.stroke(col[0], col[1], col[2], alpha);
        p.strokeWeight(lineW);
        p.line(prev2d[0], prev2d[1], cur2d[0], cur2d[1]);
      }
    }
  }
};
